      },
      {
        "name": "PostgreSQL (Leader + Sync Replica)",
        "responsibility": "Single source of truth for courier status, active assignments, and order state. Uses row-level locking (SELECT FOR UPDATE SKIP LOCKED) to serialize courier assignment and prevent double-booking.",
        "boundaries": "Leader handles all writes. Synchronous replica ensures zero data loss on failover. Patroni or pg_auto_failover manages automatic promotion."
      },
      {
        "name": "Order Ingress (API Gateway / Message Consumer)",
        "responsibility": "Accepts order placement requests, validates payload, and dispatches to Assignment Service. Returns assignment result synchronously within the 200ms budget.",
        "boundaries": "Thin layer. No business logic. If assignment fails, returns a retriable error rather than silently dropping."
      }
    ],
    "interfaces": [
      {
        "from": "Order Ingress",
        "to": "Assignment Service",
        "contract": "POST /assign {order_id, pickup_location, delivery_location} → {courier_id, estimated_pickup_time} | 409 Conflict | 503 Unavailable",
        "coupling_type": "synchronous RPC (HTTP or gRPC) — acceptable because assignment is latency-sensitive and the caller needs the result immediately"
