        "from": "Assignment Service",
        "to": "PostgreSQL",
        "contract": "Single serializable transaction: (1) SELECT candidate FROM couriers WHERE status='available' AND id IN (pre-filtered candidates) ORDER BY score LIMIT 1 FOR UPDATE SKIP LOCKED, (2) INSERT INTO assignments, (3) UPDATE couriers SET status='assigned'. Entire transaction must complete within ~50ms.",
        "coupling_type": "tight coupling to DB schema — intentional, this is the consistency boundary"
      },
      {
        "from": "Assignment Service",
        "to": "Courier Availability Cache",
        "contract": "In-process read of available courier list filtered by geo-proximity. Cache is populated via PostgreSQL LISTEN/NOTIFY on courier status changes.",
        "coupling_type": "loose — cache is an optimization, not a correctness requirement. System works without it (just slower)."
      },
      {
        "from": "PostgreSQL Leader",
        "to": "PostgreSQL Sync Replica",
        "contract": "Synchronous streaming replication. Writes are not acknowledged until replica confirms. Patroni manages failover with promotion in 5-15 seconds.",
        "coupling_type": "infrastructure coupling — managed by Patroni/pg_auto_failover, invisible to application code"
      }
